import sqlite3
from pathlib import Path


ROOT = Path(__file__).parents[1]


def load(name):
    return (ROOT / "sql" / name).read_text(encoding="utf-8")


def test_two_tenant_import_respects_each_effective_window():
    db = sqlite3.connect(":memory:")
    db.executescript(load("schema.sql"))
    write = load("upsert_grant.sql")
    for tenant, start, end in (("harbor", 5, 20), ("ridge", 10, 30)):
        db.execute(
            write,
            {
                "tenant_id": tenant,
                "principal_id": "operator-77",
                "capability": "approve",
                "valid_from": start,
                "valid_until": end,
                "revoked_at": None,
            },
        )

    query = load("effective_access.sql")
    visible = {
        "harbor": db.execute(
            query,
            {"tenant_id": "harbor", "principal_id": "operator-77", "as_of": 20},
        ).fetchall(),
        "ridge": db.execute(
            query,
            {"tenant_id": "ridge", "principal_id": "operator-77", "as_of": 20},
        ).fetchall(),
    }
    assert visible == {"harbor": [], "ridge": [("approve",)]}
